// ── DATOS: AUTOR ──

const authorData = {
  name: "Jackson Stritch",
  role: "Lead Instructor & Curriculum Designer",
  bio: "Más de 15 años formando a profesionales hispanohablantes en inglés de negocios. Ex-director de programas de idiomas en IE Business School y ESADE.",
};

// ── MIGRACIÓN ──

async function migrate() {
  console.log("🚀 Iniciando migración a Sanity...\n");

  // 1. Crear autor
  console.log("📝 Creando autor...");
  const author = await client.createOrReplace({
    _id: "author-jackson-stritch",
    _type: "author",
    ...authorData,
  });
  console.log(`   ✅ ${author.name}\n`);

  // 2. Crear categorías
  console.log("📂 Creando categorías...");
  const categoryMap = {};
  for (const cat of categories) {
    const doc = await client.createOrReplace({
      _id: `category-${cat.slug}`,
      _type: "category",
      name: cat.name,
      slug: { _type: "slug", current: cat.slug },
      color: cat.color,
      order: cat.order,
      influences: cat.influences,
    });
    categoryMap[cat.slug] = doc._id;
    console.log(`   ✅ ${cat.name}`);
  }
  console.log("");

  // 3. Crear cursos
  console.log("📚 Creando cursos...");
  const courseMap = {};
  for (const course of coursesData) {
    const doc = await client.createOrReplace({
      _id: `course-${course.slug}`,
      _type: "course",
      title: course.title,
      h1: course.h1,
      slug: { _type: "slug", current: course.slug },
      metaDescription: course.metaDescription,
      description: course.description,
      category: { _type: "reference", _ref: categoryMap[course.categorySlug] },
      author: { _type: "reference", _ref: "author-jackson-stritch" },
      tags: course.tags,
      published: true,
    });
    courseMap[course.slug] = doc._id;
  }
  console.log(`   ✅ ${coursesData.length} cursos creados\n`);

  // 4. Resumen
  console.log("═══════════════════════════════════════");
  console.log(`✅ Migración completada:`);
  console.log(`   • 1 autor`);
  console.log(`   • ${categories.length} categorías`);
  console.log(`   • ${coursesData.length} cursos`);
  console.log(`\n💡 Las lecciones del curso de ventas se mantienen en el código.`);
  console.log(`   Puedes crearlas en el panel de Sanity o migrarlas después.`);
  console.log("═══════════════════════════════════════");
}

migrate().catch((err) => {
  console.error("❌ Error en la migración:", err.message);
  process.exit(1);
});
